#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>

#define BENCH_PRINT

#define M_SEED 9

__device__ int min(int a, int b) {
    return (a <= b) ? a : b;
}

__global__ void pathfinder_kernel(int* wall, int* src, int* dst, int cols, int t) {
    int n = blockIdx.x * blockDim.x + threadIdx.x;
    if (n < cols) {
        int min_val = src[n];
        if (n > 0)
            min_val = min(min_val, src[n-1]);
        if (n < cols-1)
            min_val = min(min_val, src[n+1]);
        dst[n] = wall[t*cols + n] + min_val;
    }
}

void init(int argc, char** argv, int* rows, int* cols, int** data, int** wall, int** result) {
    if(argc==3){
        *cols = atoi(argv[1]);
        *rows = atoi(argv[2]);
    }else{
        printf("Usage: pathfiner width num_of_steps\n");
        exit(0);
    }
    *data = new int[*rows**cols];
    *wall = *data;
    *result = new int[*cols];

    int seed = M_SEED;
    srand(seed);

    for (int i = 0; i < *rows; i++)
    {
        for (int j = 0; j < *cols; j++)
        {
            (*wall)[i*(*cols)+j] = rand() % 10;
        }
    }
    for (int j = 0; j < *cols; j++)
        (*result)[j] = (*wall)[0];
#ifdef BENCH_PRINT
    for (int i = 0; i < *rows; i++)
    {
        for (int j = 0; j < *cols; j++)
        {
            printf("%d ",(*wall)[i*(*cols)+j]) ;
        }
        printf("\n") ;
    }
#endif
}

void fatal(char *s)
{
    fprintf(stderr, "error: %s\n", s);

}

int main(int argc, char** argv)
{
    int rows, cols;
    int* data;
    int* wall;
    int* result;
    init(argc, argv, &rows, &cols, &data, &wall, &result);

    unsigned long long cycles;
    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    int* src;
    int* dst;
    int* d_wall;
    int* d_src;
    int* d_dst;

    src = new int[cols];
    dst = new int[cols];

    cudaMalloc((void**)&d_wall, rows*cols*sizeof(int));
    cudaMalloc((void**)&d_src, cols*sizeof(int));
    cudaMalloc((void**)&d_dst, cols*sizeof(int));

    cudaMemcpy(d_wall, wall, rows*cols*sizeof(int), cudaMemcpyHostToDevice);

    cudaEventRecord(start);
    for (int t = 0; t < rows-1; t++) {
        cudaMemcpy(d_src, result, cols*sizeof(int), cudaMemcpyHostToDevice);
        pathfinder_kernel<<<(cols+255)/256, 256>>>(d_wall, d_src, d_dst, cols, t);
        cudaMemcpy(result, d_dst, cols*sizeof(int), cudaMemcpyDeviceToHost);
    }
    cudaEventRecord(stop);
    cudaEventSynchronize(stop);
    float milliseconds = 0;
    cudaEventElapsedTime(&milliseconds, start, stop);
    printf("timer: %f\n", milliseconds);

#ifdef BENCH_PRINT
    for (int i = 0; i < cols; i++)
        printf("%d ",result[i]) ;
    printf("\n") ;
#endif

    delete [] data;
    delete [] result;
    delete [] src;
    delete [] dst;
    cudaFree(d_wall);
    cudaFree(d_src);
    cudaFree(d_dst);

    return EXIT_SUCCESS;
}
